    cpu.mem[sym::lightning] = 0x05;
    cpu.reg.a = 0x05;
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
    crate::ext::addsound(cpu);
