    crate::ext::getunderft(cpu);
    if cpu.reg.a != 0x0d {
        return;
    }
    getreflect(cpu);
    cpu.reg.a = cpu.mem[sym::dmirr];
    cpu.flags.z = cpu.reg.a == 0;
    cpu.flags.n = (cpu.reg.a >> 7) != 0;
